function ZapIn(
        address _staker,
        uint256 _minPoolTokens,
        address payable _agent
    ) public payable nonReentrant stopInEmergency returns (uint256) {
        require(msg.value > 0, "Error: ETH not sent");
        if(msg.sender == _agent || !(agentRegistry.isAgent(_agent))){
            _agent = address(0);
        }
        
        // Default
        uint256 toVault = msg.value.mul(goodwill).div(10000); // 10% to vault
        uint256 toInvest = msg.value.sub(toVault); // 90% to swap
        
        // And if it is referred by an agent
        if(_agent != address(0)){
            toVault = msg.value.mul(500).div(10000); // 5% to vault
            toInvest = msg.value.mul(9250).div(10000); // 92.5% to swap
            uint256 toAgent = msg.value.sub(toVault).sub(toInvest); // 2.5% to agent
            // Transfer to agnet
            _agent.transfer(toAgent);
            referralRewards[_agent] = referralRewards[_agent].add(toAgent);
            emit AmountToAgent(msg.sender, _agent, toAgent);
        }

        // Transfer to vault
        vault.transfer(toVault);
        emit AmountToVault(msg.sender, toVault);
        // Single sided add liquidity
        uint256 LPBought = _performZapIn(
            _staker,
            ethTokenAddress,
            TOKEN_ADDRESS_711,
            wethTokenAddress,
            toInvest
        );
        emit AmountToInvest(msg.sender, toInvest, LPBought);
        require(LPBought >= _minPoolTokens, "ERR: High Slippage");

        // Stake LP token
        IERC20(UNISWAP_V2_PAIR_711_WETH).safeApprove(stakingContract, LPBought);
        IStakingRewards(stakingContract).stakeFor(_staker, LPBought);

        return LPBought;
    }

function deposit(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(block.timestamp < pool.endDate, "staking pool already closed");

        updatePool(_pid);

        if (user.amount > 0) {
            uint256 pending =
                user.amount.mul(pool.accTokenPerShare).div(1e18).sub(
                    user.rewardDebt
                );
            if (pending > 0) {
                safeTokenTransfer(msg.sender, pending, _pid);
                pool.totalTokenClaimed = pool.totalTokenClaimed.add(pending);
                user.rewardClaimed = user.rewardClaimed.add(pending);
            }
        } else {
            //new user, or old user unstake all before
            totalUser = totalUser.add(1);
            user.beginTime = block.timestamp;
            user.endTime = 0; //reset endtime
        }
        if (_amount > 0) {
            pool.stakeToken.safeTransferFrom(
                address(msg.sender),
                address(this),
                _amount
            );
            user.amount = user.amount.add(_amount);
            pool.totalTokenStaked = pool.totalTokenStaked.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accTokenPerShare).div(1e18);
        user.lastBlock = block.number;
        emit Deposit(msg.sender, _pid, _amount);
    }

function depositToken(address token, uint256 amount, uint256 unlock_date) public payable {
        require(unlock_date < 10000000000, 'Enter an unix timestamp in seconds, not miliseconds');
        require(amount > 0, 'Your attempting to trasfer 0 tokens');
        uint256 allowance = IERC20(token).allowance(msg.sender, address(this));
        require(allowance >= amount, 'You need to set a higher allowance');
        // charge a fee
        uint256 fee = calculateFee(amount);
        uint256 amountIn = amount.sub(fee);
        require(IERC20(token).transferFrom(msg.sender, address(this), amountIn), 'Transfer failed');
        require(IERC20(token).transferFrom(msg.sender, address(feeReserveAddress), fee), 'Transfer failed');
        if (!lockedTokenLookup[token]) {
            lockedTokens.push(token);
            lockedTokenLookup[token] = true;
        }
        LiquidityTokenomics storage liquidityTokenomics = tokenEpochMap[token];
        // amount is required to be above 0 in the start of this block, therefore this works
        if (liquidityTokenomics.releaseMap[unlock_date] > 0) {
            liquidityTokenomics.releaseMap[unlock_date] = liquidityTokenomics.releaseMap[unlock_date].add(amountIn);
        } else {
            liquidityTokenomics.epochs.push(unlock_date);
            liquidityTokenomics.releaseMap[unlock_date] = amountIn;
        }
        UserTokenInfo storage uto = tokenUserMap[token][msg.sender];
        uto.deposited = uto.deposited.add(amountIn);
        VestingPeriod[] storage vp = uto.vestingPeriods;
        vp.push(VestingPeriod(unlock_date, amountIn));

        emit onDeposit(token, amount, unlock_date);
    }

function withdrawFunds(uint left,uint right,address winner,uint reward) public isAdmin{
    require(getWinningIndex().sub(left)!=getWinningIndex().add(right),"w1");//checked indexes should be different positions
    require(getWinningIndex()!=0,"w2");
    uint leftval=token_map[current_round][getWinningIndex().sub(left)];
    uint rightval=token_map[current_round][getWinningIndex().add(right)];
    require(leftval!=0,"w3");//both checked indexes should be nonzero
    require(leftval==rightval,"w4");//both checked values should be the same
    require(winner == entry_map[current_round][leftval],"w5");//check that the proposed winner actually submitted the given entry

    //uint cbal=liquidityToken.balanceOf(address(this));
    require(startingLiquidityTokens.mul(maxRewardable).div(100)>=reward,"cannot reward too large a portion");
    liquidityToken.transfer(winner,reward);

    current_round+=1;
    entry_cursor=0;
    cursor=0;
    winningIndex=0;
    finalizingLock=false;
    finalizationBlock=0;
  }

function create(address _token, address payable _beneficiary, uint256 _cliff, uint256 _vesting, uint256 _amount, bool _irrevocable) public returns (uint256 ticketId) {
      /// @dev sender needs to approve this contract to fund the claim
      require(_beneficiary != address(0), "Beneficiary is required");
      require(_amount > 0, "Amount is required");
      require(_vesting >= _cliff, "Vesting period should be equal or longer to the cliff");
      ERC20 token = ERC20(_token);
      require(token.balanceOf(_msgSender()) >= _amount, "Insufficient balance");
      require(token.transferFrom(_msgSender(), address(this), _amount), "Funding failed.");
      ticketId = ++currentId;
      Ticket storage ticket = tickets[ticketId];
      ticket.token = _token;
      ticket.grantor = _msgSender();
      ticket.beneficiary = _beneficiary;
      ticket.cliff = _cliff;
      ticket.vesting = _vesting;
      ticket.amount = _amount;
      ticket.balance = _amount;
      ticket.createdAt = block.timestamp;
      ticket.irrevocable = _irrevocable;
      grantorTickets[_msgSender()].push(ticketId);
      beneficiaryTickets[_beneficiary].push(ticketId);
      emit TicketCreated(ticketId, _token, _amount, _irrevocable);
    }

function withdraw(uint256 _pid, uint256 _amount) public {
		PoolInfo storage pool = poolInfo[_pid];
		UserInfo storage user = userInfo[_pid][msg.sender];
		require(user.amount >= _amount, 'withdraw: not good');
		updatePool(_pid);
		uint256 pending = user.amount.mul(pool.accPerShare).div(1e12).sub(
			user.rewardDebt
		);
		uint256 burnPending = 0;
		if (pending > 0) {
			burnPending = pending.mul(unstakeBurnRate).div(10000);
			uint256 sendPending = pending.sub(burnPending);
			if (token.totalSupply().sub(burnPending) < token.minSupply()) {
				burnPending = 0;
				sendPending = pending;
			}
			safeTokenTransfer(msg.sender, sendPending);
			if (burnPending > 0) {
				totalUnstakeBurn = totalUnstakeBurn.add(burnPending);
				token.burn(burnPending);
			}
		}
		if (_amount > 0) {
			user.amount = user.amount.sub(_amount);
			pool.lpToken.safeTransfer(address(msg.sender), _amount);
		}
		user.rewardDebt = user.amount.mul(pool.accPerShare).div(1e12);
		emit Withdraw(msg.sender, _pid, _amount);
	}

